def test_manager_updates_employee_success(auth_client, audit_db):
    emp_id = 42
    payload = {
        "first_name": "John",
        "last_name": "Doe",
        "email": "john@example.com"
    }
    resp = auth_client.post(f"/employees/{emp_id}", json=payload)
    assert resp.status_code in [200, 201]
    assert resp.json()["id"] == emp_id
    audit_entry = audit_db.find_one({
        "employee_id": emp_id,
        "action": "UPDATE"
    })
    assert audit_entry is not None
    assert "timestamp" in audit_entry

def test_manager_updates_employee_missing_mandatory_field(auth_client, audit_db):
    emp_id = 42
    payload = {"first_name": "John"}
    resp = auth_client.post(f"/employees/{emp_id}", json=payload)
    assert resp.status_code == 400
    assert "last_name" in resp.json()["errors"] or "email" in resp.json()["errors"]
    audit_count = audit_db.count_documents({
        "employee_id": emp_id,
        "action": "UPDATE"
    })
    assert audit_count == 0

def test_manager_updates_employee_forbidden_role(employee_client):
    emp_id = 42
    payload = {"first_name": "Jane", "last_name": "Smith", "email": "jane@example.com"}
    resp = employee_client.post(f"/employees/{emp_id}", json=payload)
    assert resp.status_code == 403
    assert "permission" in resp.json()["message"].lower()

def test_manager_updates_employee_invalid_email_format(auth_client):
    emp_id = 42
    payload = {
        "first_name": "John",
        "last_name": "Doe",
        "email": "invalid-email-format"
    }
    resp = auth_client.post(f"/employees/{emp_id}", json=payload)
    assert resp.status_code == 400
    assert "email" in resp.json()["errors"]
